// cSpell:disable// ignore_for_file: type=lint, unused_field, prefer_const_constructors, prefer_const_literals_to_create_immutables, use_build_context_synchronously, avoid_printimport 'dart:io';import 'dart:convert'; // Thêm để xử lý định dạng JSON gửi lên Google Sheetsimport 'package:flutter/material.dart';import 'package:firebase_auth/firebase_auth.dart';import 'package:cloud_firestore/cloud_firestore.dart';import 'package:intl/intl.dart';import 'package:url_launcher/url_launcher.dart';import 'package:flutter_local_notifications/flutter_local_notifications.dart';import 'package:timezone/timezone.dart' as tz;import 'package:timezone/data/latest.dart' as tz;import 'package:provider/provider.dart';import 'package:shared_preferences/shared_preferences.dart';import 'package:image_picker/image_picker.dart';import 'package:http/http.dart' as http; // Thư viện để gửi dữ liệu qua APIimport 'theme_provider.dart';import 'login.dart';import 'admin_page.dart';class HomeScreen extends StatefulWidget {  const HomeScreen({super.key});  @override  State<HomeScreen> createState() => _HomeScreenState();}class _HomeScreenState extends State<HomeScreen> {  // --- CÁC BIẾN TRẠNG THÁI GIAO DIỆN (UI STATE) ---  int _currentIndex = 0; // Biến lưu index của BottomNavigationBar  bool isVietnamese = true; // Cờ theo dõi ngôn ngữ hiện tại (Việt/Anh)  // --- CÁC CONTROLLER ĐIỀU KHIỂN TEXTFIELD ---  final ScrollController _scrollController = ScrollController();  final TextEditingController _searchController = TextEditingController();  final TextEditingController _chatController = TextEditingController();  // Controllers cho phần Đặt lịch khám (Thông tin bệnh nhân)  final TextEditingController _nameController = TextEditingController();  final TextEditingController _phoneController = TextEditingController();  final TextEditingController _addressController = TextEditingController();  final TextEditingController _emailController = TextEditingController();  // Controllers cho phần đổi mật khẩu  final TextEditingController _currentPasswordController =      TextEditingController();  final TextEditingController _newPasswordController = TextEditingController();  final TextEditingController _confirmPasswordController =      TextEditingController();  // Controller cho phần đổi tên người dùng  final TextEditingController _editNameController = TextEditingController();  // --- BIẾN NGƯỜI DÙNG & DỮ LIỆU ---  final User? user = FirebaseAuth      .instance      .currentUser; // Lấy thông tin user hiện tại từ Firebase  bool _isTyping = false; // Cờ hiệu ứng chatbot đang gõ tin nhắn  // Biến lưu trữ thông tin Hồ sơ cá nhân  String _userName = "";  String _profileImagePath = "";  // Plugin xử lý thông báo nội bộ (Local Notifications)  final FlutterLocalNotificationsPlugin flutterLocalNotificationsPlugin =      FlutterLocalNotificationsPlugin();  // --- BỘ TỪ ĐIỂN ĐA NGÔN NGỮ (VI - EN) ---  Map<String, dynamic> get lang => {    'home': isVietnamese ? "Trang chủ" : "Home",    'booking': isVietnamese ? "Lịch hẹn" : "Appointment",    'chat': isVietnamese ? "Tin nhắn" : "Message",    'profile': isVietnamese ? "Hồ sơ" : "Profile",    'welcome': isVietnamese ? "Chào bạn! 👋" : "Hello! 👋",    'find_doc': isVietnamese ? "Tìm bác sĩ của bạn" : "Find your doctor",    'search_hint': isVietnamese ? "Tìm bác sĩ..." : "Search doctor...",    'dept': isVietnamese ? "Chuyên khoa" : "Speciality",    'all': isVietnamese ? "Xem tất cả" : "See all",    'book_btn': isVietnamese ? "Bấm để đặt lịch" : "Book now",    'my_booking': isVietnamese ? "Lịch hẹn của bạn" : "Your Appointments",    'no_booking': isVietnamese        ? "Chưa có lịch hẹn nào."        : "No appointments yet.",    'patient': isVietnamese ? "Tên người khám" : "Patient Name",    'phone': isVietnamese ? "Số điện thoại" : "Phone Number",    'address': isVietnamese ? "Địa chỉ" : "Address",    'email': isVietnamese ? "Email" : "Email",    'change_pw': isVietnamese ? "Đổi mật khẩu" : "Change Password",    'logout': isVietnamese ? "Đăng xuất" : "Logout",    'call_hotline': isVietnamese ? "Gọi Hotline" : "Call Hotline",    'chat_hint': isVietnamese ? "Nhập tin nhắn..." : "Type a message...",    'bot_typing': isVietnamese ? "Bác sĩ đang gõ..." : "Doctor is typing...",    'reset_chat': isVietnamese ? "Làm mới chat" : "Reset chat",    'select_hosp': isVietnamese ? "Chọn nơi khám bệnh" : "Select Hospital",    'hosp_title': isVietnamese ? "Danh sách bệnh viện" : "Hospital List",    'back_hosp': isVietnamese ? "Đổi bệnh viện" : "Change Hospital",    'hosp_desc': isVietnamese        ? "Vui lòng chọn bệnh viện để xem bác sĩ"        : "Choose a hospital to see doctors",    'dark_mode': isVietnamese ? "Chế độ tối" : "Dark Mode",    'admin_panel': isVietnamese ? "Trang Quản Trị" : "Admin Panel",    'select_slot': isVietnamese        ? "Chọn ca khám còn trống"        : "Select available slot",    'edit_name': isVietnamese ? "Đổi tên hiển thị" : "Change Name",    'enter_name': isVietnamese ? "Nhập tên mới" : "Enter new name",    'cancel': isVietnamese ? "Hủy" : "Cancel",    'save': isVietnamese ? "Lưu" : "Save",    'name_success': isVietnamese ? "Đổi tên thành công!" : "Name updated!",    'appt_details': isVietnamese ? "Chi tiết lịch hẹn" : "Appointment Details",    'close': isVietnamese ? "Đóng" : "Close",    // Ngôn ngữ cho chức năng Đổi Mật Khẩu    'current_pw': isVietnamese ? "Mật khẩu hiện tại" : "Current Password",    'new_pw': isVietnamese ? "Mật khẩu mới" : "New Password",    'confirm_pw': isVietnamese ? "Xác nhận mật khẩu mới" : "Confirm Password",    'pw_not_match': isVietnamese        ? "Mật khẩu xác nhận không khớp!"        : "Passwords do not match!",    'pw_success': isVietnamese        ? "Đổi mật khẩu thành công!"        : "Password changed!",    'pw_error': isVietnamese        ? "Sai mật khẩu hiện tại hoặc lỗi mạng!"        : "Wrong current password or network error!",    'fill_all': isVietnamese        ? "Vui lòng điền đủ thông tin!"        : "Please fill all fields!",  };  // --- CÁC BIẾN LƯU BỘ LỌC DỮ LIỆU ---  String? _selectedHospital;  String? _selectedDeptFilter;  List<Map<String, dynamic>> bookedAppointments = [];  List<Map<String, dynamic>> _messages = [];  // Danh sách các ca khám mặc định (từ 08:00 đến 22:00)  final List<String> _timeSlots = [    "08:00",    "08:30",    "09:00",    "09:30",    "10:00",    "10:30",    "13:30",    "14:00",    "14:30",    "15:00",    "15:30",    "16:00",    "16:30",    "17:00",    "17:30",    "18:00",    "18:30",    "19:00",    "19:30",    "20:00",    "20:30",    "21:00",    "21:30",    "22:00",  ];  // --- HÀM KHỞI TẠO (CHẠY LẦN ĐẦU KHI VÀO MÀN HÌNH) ---  @override  void initState() {    super.initState();    _resetChat(); // Khởi tạo dữ liệu chatbot mặc định    _initNotifications(); // Cấu hình quyền thông báo cho thiết bị    _loadAppState(); // Tải trạng thái ngôn ngữ và hồ sơ từ bộ nhớ máy    _fetchAppointments(); // Lấy danh sách lịch hẹn của user từ Firestore  }  // --- HÀM HỦY (GIẢI PHÓNG BỘ NHỚ KHI ĐÓNG MÀN HÌNH) ---  @override  void dispose() {    _editNameController.dispose();    _currentPasswordController.dispose();    _newPasswordController.dispose();    _confirmPasswordController.dispose();    _nameController.dispose();    _phoneController.dispose();    _addressController.dispose();    _emailController.dispose();    super.dispose();  }  // --- HÀM DỊCH THUẬT VÀ LỌC TÊN CHUYÊN KHOA ---  String _getDisplayName(String name) {    if (isVietnamese) return name;    String key = name.toLowerCase().trim();    // Thuật toán xóa dấu tiếng Việt để làm key so khớp    key = key.replaceAll(RegExp(r'[àáạảãâầấậẩẫăằắặẳẵ]'), 'a');    key = key.replaceAll(RegExp(r'[èéẹẻẽêềếệểễ]'), 'e');    key = key.replaceAll(RegExp(r'[ìíịỉĩ]'), 'i');    key = key.replaceAll(RegExp(r'[òóọỏõôồốộổỗơờớợởỡ]'), 'o');    key = key.replaceAll(RegExp(r'[ùúụủũưừứựửữ]'), 'u');    key = key.replaceAll(RegExp(r'[ỳýỵỷỹ]'), 'y');    key = key.replaceAll(RegExp(r'[đ]'), 'd');    // Map chuyển đổi ngôn ngữ cho chuyên khoa    Map<String, String> translation = {      "tim mach": "Cardiology",      "mat": "Ophthalmology",      "nhi khoa": "Pediatrics",      "tam than": "Psychiatry",      "chinh hinh": "Orthopedics",      "noi khoa": "Internal Medicine",      "ngoai khoa": "Surgery",      "da lieu": "Dermatology",      "tai mui hong": "ENT",      "rang ham mat": "Dentistry",      "ung buou": "Oncology",      "phu khoa": "Gynecology",      "da khoa": "General Clinic",      "than": "Nephrology",      "tieu hoa": "Gastroenterology",    };    return translation[key] ?? name;  }  // --- HÀM TỰ ĐỘNG GÁN ICON THEO Tên Chuyên Khoa ---  IconData _getIconForSpeciality(String name) {    name = name.toLowerCase();    if (name.contains("tim") || name.contains("mạch"))      return Icons.favorite_rounded;    if (name.contains("nhi") || name.contains("trẻ"))      return Icons.child_care_rounded;    if (name.contains("mắt")) return Icons.visibility_rounded;    if (name.contains("tâm thần") || name.contains("não"))      return Icons.psychology_rounded;    if (name.contains("chỉnh hình") || name.contains("xương"))      return Icons.healing_rounded;    if (name.contains("nội")) return Icons.medical_services_rounded;    if (name.contains("ngoại")) return Icons.biotech_rounded;    if (name.contains("da liễu")) return Icons.face_retouching_natural_rounded;    if (name.contains("tai") || name.contains("mũi") || name.contains("họng"))      return Icons.hearing_rounded;    if (name.contains("răng") || name.contains("hàm"))      return Icons.sentiment_satisfied_alt;    return Icons.label_important_outline;  }  // --- HÀM NHÓM LỊCH HẸN THEO THÁNG ---  Map<String, List<Map<String, dynamic>>> _groupAppointmentsByMonth() {    Map<String, List<Map<String, dynamic>>> groups = {};    List<Map<String, dynamic>> sortedList = List.from(bookedAppointments);    // Sắp xếp từ mới nhất đến cũ nhất    sortedList.sort(      (a, b) => (b['fullDateTime'] as DateTime).compareTo(        a['fullDateTime'] as DateTime,      ),    );    for (var app in sortedList) {      DateTime date = app['fullDateTime'] as DateTime;      String monthKey = isVietnamese          ? "Tháng ${DateFormat('MM, yyyy').format(date)}"          : DateFormat('MMMM yyyy').format(date);      if (groups[monthKey] == null) groups[monthKey] = [];      groups[monthKey]!.add(app);    }    return groups;  }  // --- TẢI TRẠNG THÁI ỨNG DỤNG TỪ BỘ NHỚ TẠM ---  void _loadAppState() async {    final prefs = await SharedPreferences.getInstance();    setState(() {      isVietnamese = prefs.getBool('isVietnamese') ?? true;      _profileImagePath = prefs.getString('profileImagePath') ?? "";      // Ưu tiên hiển thị tên người dùng đã đặt, nếu chưa có lấy email      _userName = user?.displayName != null && user!.displayName!.isNotEmpty          ? user!.displayName!          : (user?.email ?? "User");    });  }  // --- HÀM CHỌN ẢNH ĐẠI DIỆN TỪ THƯ VIỆN ---  Future<void> _pickImage() async {    final ImagePicker picker = ImagePicker();    final XFile? image = await picker.pickImage(source: ImageSource.gallery);    if (image != null) {      final prefs = await SharedPreferences.getInstance();      await prefs.setString(        'profileImagePath',        image.path,      ); // Lưu đường dẫn cục bộ      setState(() {        _profileImagePath = image.path; // Cập nhật giao diện ngay      });    }  }  // --- HÀM ĐỔI TÊN HIỂN THỊ NGƯỜI DÙNG ---  Future<void> _editName() async {    _editNameController.text = _userName == (user?.email ?? "User")        ? ""        : _userName;    final String? newName = await showDialog<String>(      context: context,      builder: (ctx) => AlertDialog(        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(20)),        title: Text(          lang['edit_name'],          style: const TextStyle(fontWeight: FontWeight.bold),        ),        content: TextField(          controller: _editNameController,          autofocus: true,          decoration: InputDecoration(            hintText: lang['enter_name'],            border: OutlineInputBorder(borderRadius: BorderRadius.circular(15)),          ),        ),        actions: [          TextButton(            onPressed: () => Navigator.pop(ctx),            child: Text(              lang['cancel'],              style: const TextStyle(color: Colors.grey),            ),          ),          ElevatedButton(            onPressed: () => Navigator.pop(ctx, _editNameController.text),            style: ElevatedButton.styleFrom(backgroundColor: Colors.blue),            child: Text(              lang['save'],              style: const TextStyle(color: Colors.white),            ),          ),        ],      ),    );    if (newName != null && newName.trim().isNotEmpty) {      try {        await user?.updateDisplayName(          newName.trim(),        ); // Cập nhật lên Firebase Auth        setState(() {          _userName = newName.trim();        });        if (mounted) {          ScaffoldMessenger.of(context).showSnackBar(            SnackBar(              content: Text(lang['name_success']),              backgroundColor: Colors.green,            ),          );        }      } catch (e) {        debugPrint("Lỗi đổi tên: $e");      }    }  }  // --- HÀM ĐỔI MẬT KHẨU TÀI KHOẢN ---  Future<void> _showChangePasswordDialog() async {    _currentPasswordController.clear();    _newPasswordController.clear();    _confirmPasswordController.clear();    bool isLoading = false;    await showDialog(      context: context,      barrierDismissible: false,      builder: (ctx) => StatefulBuilder(        builder: (context, setDialogState) {          return AlertDialog(            shape: RoundedRectangleBorder(              borderRadius: BorderRadius.circular(20),            ),            title: Text(              lang['change_pw'],              style: const TextStyle(fontWeight: FontWeight.bold),            ),            content: Column(              mainAxisSize: MainAxisSize.min,              children: [                TextField(                  controller: _currentPasswordController,                  obscureText: true,                  decoration: InputDecoration(                    labelText: lang['current_pw'],                    prefixIcon: const Icon(Icons.lock_clock),                    border: OutlineInputBorder(                      borderRadius: BorderRadius.circular(15),                    ),                  ),                ),                const SizedBox(height: 15),                TextField(                  controller: _newPasswordController,                  obscureText: true,                  decoration: InputDecoration(                    labelText: lang['new_pw'],                    prefixIcon: const Icon(Icons.lock_reset),                    border: OutlineInputBorder(                      borderRadius: BorderRadius.circular(15),                    ),                  ),                ),                const SizedBox(height: 15),                TextField(                  controller: _confirmPasswordController,                  obscureText: true,                  decoration: InputDecoration(                    labelText: lang['confirm_pw'],                    prefixIcon: const Icon(Icons.lock_person),                    border: OutlineInputBorder(                      borderRadius: BorderRadius.circular(15),                    ),                  ),                ),              ],            ),            actions: [              TextButton(                onPressed: isLoading ? null : () => Navigator.pop(ctx),                child: Text(                  lang['cancel'],                  style: const TextStyle(color: Colors.grey),                ),              ),              ElevatedButton(                onPressed: isLoading                    ? null                    : () async {                        String currentPw = _currentPasswordController.text                            .trim();                        String newPw = _newPasswordController.text.trim();                        String confirmPw = _confirmPasswordController.text                            .trim();                        if (currentPw.isEmpty ||                            newPw.isEmpty ||                            confirmPw.isEmpty) {                          ScaffoldMessenger.of(context).showSnackBar(                            SnackBar(                              content: Text(lang['fill_all']),                              backgroundColor: Colors.orange,                            ),                          );                          return;                        }                        if (newPw != confirmPw) {                          ScaffoldMessenger.of(context).showSnackBar(                            SnackBar(                              content: Text(lang['pw_not_match']),                              backgroundColor: Colors.orange,                            ),                          );                          return;                        }                        setDialogState(() => isLoading = true);                        try {                          // Xác thực lại tài khoản trước khi đổi mật khẩu                          AuthCredential credential =                              EmailAuthProvider.credential(                                email: user!.email!,                                password: currentPw,                              );                          await user!.reauthenticateWithCredential(credential);                          await user!.updatePassword(                            newPw,                          ); // Thực hiện cập nhật mật khẩu mới                          if (mounted) {                            Navigator.pop(ctx);                            ScaffoldMessenger.of(context).showSnackBar(                              SnackBar(                                content: Text(lang['pw_success']),                                backgroundColor: Colors.green,                              ),                            );                          }                        } catch (e) {                          setDialogState(() => isLoading = false);                          if (mounted) {                            ScaffoldMessenger.of(context).showSnackBar(                              SnackBar(                                content: Text(lang['pw_error']),                                backgroundColor: Colors.redAccent,                              ),                            );                          }                        }                      },                style: ElevatedButton.styleFrom(backgroundColor: Colors.blue),                child: isLoading                    ? const SizedBox(                        width: 20,                        height: 20,                        child: CircularProgressIndicator(                          color: Colors.white,                          strokeWidth: 2,                        ),                      )                    : Text(                        lang['save'],                        style: const TextStyle(color: Colors.white),                      ),              ),            ],          );        },      ),    );  }  // --- LẤY DANH SÁCH LỊCH HẸN TỪ CLOUD FIRESTORE ---  void _fetchAppointments() async {    if (user == null) return;    try {      final snapshot = await FirebaseFirestore.instance          .collection('appointments')          .where('userId', isEqualTo: user?.uid)          .get();      final List<Map<String, dynamic>> loadedData = snapshot.docs.map((doc) {        final data = doc.data();        return {          'id': doc.id,          'name': data['doctorName'] ?? 'Bác sĩ',          'image': data['image'] ?? 'assets/images/logo.png',          'patient': data['patientName'] ?? 'Bệnh nhân',          'phone': data['patientPhone'] ?? '',          'address': data['patientAddress'] ?? '',          'email': data['patientEmail'] ?? '',          'hospital': data['hospital'] ?? 'Bệnh viện chưa xác định',          'date': data['date'] ?? '',          'time': data['time'] ?? '',          'dept': data['dept'] ?? '',          'fullDateTime': data['fullDateTime'] != null              ? DateTime.parse(data['fullDateTime'])              : DateTime.now(),        };      }).toList();      setState(() {        bookedAppointments = loadedData;      });    } catch (e) {      debugPrint("Lỗi tải lịch hẹn: $e");    }  }  // --- KHỞI TẠO CẤU HÌNH THÔNG BÁO ---  void _initNotifications() async {    const AndroidInitializationSettings initializationSettingsAndroid =        AndroidInitializationSettings('@mipmap/ic_launcher');    const InitializationSettings initializationSettings =        InitializationSettings(android: initializationSettingsAndroid);    await flutterLocalNotificationsPlugin.initialize(initializationSettings);    final platform = flutterLocalNotificationsPlugin        .resolvePlatformSpecificImplementation<          AndroidFlutterLocalNotificationsPlugin        >();    if (platform != null) {      await platform.requestNotificationsPermission();    }    tz.initializeTimeZones();  }  // --- GỬI THÔNG BÁO ĐẶT LỊCH THÀNH CÔNG ---  Future<void> _showNotification(    String patientName,    String doctorName,    String time,  ) async {    const AndroidNotificationDetails androidPlatformChannelSpecifics =        AndroidNotificationDetails(          'mediapp_booking_channel',          'Thông báo Mediapp',          importance: Importance.max,          priority: Priority.high,          showWhen: true,          icon: '@mipmap/ic_launcher',        );    const NotificationDetails platformChannelSpecifics = NotificationDetails(      android: androidPlatformChannelSpecifics,    );    await flutterLocalNotificationsPlugin.show(      DateTime.now().millisecond,      isVietnamese          ? 'Mediapp: Đặt lịch thành công! ✅'          : 'Mediapp: Booking Success! ✅',      isVietnamese          ? 'Bệnh nhân $patientName có lịch với $doctorName vào $time'          : 'Patient $patientName has a schedule with $doctorName at $time',      platformChannelSpecifics,    );  }  // --- HÀM LÀM MỚI CHATBOT ---  void _resetChat() {    setState(() {      _messages = [        {          "text": isVietnamese              ? "Chào bạn! Tôi là chatbot bác sĩ. Bạn cần hỗ trợ gì?"              : "Hello ! I am your AI Doctor. How can I help you?",          "isMe": false,        },      ];    });  }  // --- XỬ LÝ GỬI TIN NHẮN CHO CHATBOT ---  void _handleSendMessage() {    String text = _chatController.text.trim();    if (text.isEmpty) return;    setState(() {      _messages.add({"text": text, "isMe": true});      _isTyping = true;    });    _chatController.clear();    Future.delayed(const Duration(milliseconds: 1500), () {      if (mounted) {        String resp = _getBotResponse(text);        setState(() {          _messages.add({"text": resp, "isMe": false});          _isTyping = false;        });      }    });  }  // --- LOGIC PHẢN HỒI CỦA BOT ---  String _getBotResponse(String input) {    input = input.toLowerCase();    if (isVietnamese) {      if (input.contains("chào"))        return "Chào bạn! Chúc bạn ngày mới tốt lành.";      return "Bác sĩ đã nhận được thông tin từ bạn!";    } else {      return "Doctor has received your message!";    }  }  // --- GỌI ĐIỆN HOTLINE ---  Future<void> _makePhoneCall(String phoneNumber) async {    final Uri launchUri = Uri(scheme: 'tel', path: phoneNumber);    if (await canLaunchUrl(launchUri)) {      await launchUrl(launchUri);    }  }  // --- HÀM XỬ LÝ LÔ GÍC ĐẶT LỊCH (ĐÃ FIX OVERFLOW VÀ TÍCH HỢP GOOGLE SHEETS) ---  Future<void> _bookDoctor(Map<String, dynamic> doc) async {    final DateTime? d = await showDatePicker(      context: context,      initialDate: DateTime.now(),      firstDate: DateTime.now(),      lastDate: DateTime(2027),    );    if (d == null) return;    String dateStr = DateFormat('dd/MM/yyyy').format(d);    showDialog(      context: context,      barrierDismissible: false,      builder: (ctx) => const Center(child: CircularProgressIndicator()),    );    List<String> takenSlots = [];    try {      final snapshot = await FirebaseFirestore.instance          .collection('appointments')          .where('doctorName', isEqualTo: doc['name'])          .get();      for (var element in snapshot.docs) {        final data = element.data();        if (data['date'] == dateStr) {          takenSlots.add(data['time'].toString());        }      }    } catch (e) {      debugPrint("Lỗi tải ca khám: $e");    }    if (mounted) Navigator.of(context, rootNavigator: true).pop();    _nameController.clear();    _phoneController.clear();    _addressController.clear();    _emailController.clear();    String? selectedTime;    if (!mounted) return;    final bool? confirmed = await showModalBottomSheet<bool>(      context: context,      isScrollControlled: true,      backgroundColor: Colors.transparent,      builder: (ctx) => StatefulBuilder(        builder: (context, setModalState) {          bool isFormValid =              selectedTime != null &&              _nameController.text.trim().isNotEmpty &&              _phoneController.text.trim().isNotEmpty &&              _addressController.text.trim().isNotEmpty &&              _emailController.text.trim().isNotEmpty;          return Padding(            padding: EdgeInsets.only(              bottom: MediaQuery.of(ctx).viewInsets.bottom,            ),            child: Container(              decoration: BoxDecoration(                color: Theme.of(context).scaffoldBackgroundColor,                borderRadius: const BorderRadius.vertical(                  top: Radius.circular(30),                ),              ),              child: SingleChildScrollView(                padding: const EdgeInsets.all(25),                child: Column(                  mainAxisSize: MainAxisSize.min,                  crossAxisAlignment: CrossAxisAlignment.start,                  children: [                    Center(                      child: Container(                        width: 40,                        height: 5,                        decoration: BoxDecoration(                          color: Colors.grey[300],                          borderRadius: BorderRadius.circular(10),                        ),                      ),                    ),                    const SizedBox(height: 20),                    Text(                      lang['select_slot'],                      style: const TextStyle(                        fontSize: 18,                        fontWeight: FontWeight.bold,                      ),                    ),                    const SizedBox(height: 15),                    // LƯỚI KHUNG GIỜ KHÁM                    Wrap(                      spacing: 10,                      runSpacing: 10,                      children: _timeSlots.map((time) {                        bool isTaken = takenSlots.contains(time);                        bool isSelected = selectedTime == time;                        bool isDark =                            Theme.of(context).brightness == Brightness.dark;                        return ChoiceChip(                          label: Text(time),                          selected: isSelected,                          onSelected: isTaken                              ? null                              : (selected) {                                  setModalState(() => selectedTime = time);                                },                          selectedColor: Colors.blue,                          labelStyle: TextStyle(                            color: isTaken                                ? Colors.grey                                : (isSelected                                      ? Colors.white                                      : (isDark                                            ? Colors.white                                            : Colors.blue.shade900)),                            fontWeight: isSelected                                ? FontWeight.bold                                : FontWeight.normal,                          ),                          backgroundColor: isTaken                              ? (isDark ? Colors.grey[800] : Colors.grey[300])                              : Colors.blue.withOpacity(0.1),                        );                      }).toList(),                    ),                    const SizedBox(height: 25),                    // CÁC Ô NHẬP LIỆU THÔNG TIN BỆNH NHÂN                    _buildBookingTextField(                      controller: _nameController,                      label: lang['patient'],                      icon: Icons.person,                      onChanged: (v) => setModalState(() {}),                    ),                    const SizedBox(height: 15),                    _buildBookingTextField(                      controller: _phoneController,                      label: lang['phone'],                      icon: Icons.phone,                      keyboardType: TextInputType.phone,                      onChanged: (v) => setModalState(() {}),                    ),                    const SizedBox(height: 15),                    _buildBookingTextField(                      controller: _addressController,                      label: lang['address'],                      icon: Icons.location_on,                      onChanged: (v) => setModalState(() {}),                    ),                    const SizedBox(height: 15),                    _buildBookingTextField(                      controller: _emailController,                      label: lang['email'],                      icon: Icons.email,                      keyboardType: TextInputType.emailAddress,                      onChanged: (v) => setModalState(() {}),                    ),                    const SizedBox(height: 25),                    // NÚT XÁC NHẬN ĐẶT LỊCH                    SizedBox(                      width: double.infinity,                      height: 55,                      child: ElevatedButton(                        onPressed: isFormValid                            ? () => Navigator.pop(ctx, true)                            : null,                        style: ElevatedButton.styleFrom(                          backgroundColor: Colors.blue,                          shape: RoundedRectangleBorder(                            borderRadius: BorderRadius.circular(15),                          ),                        ),                        child: Text(                          lang['book_btn'],                          style: const TextStyle(                            color: Colors.white,                            fontWeight: FontWeight.bold,                            fontSize: 16,                          ),                        ),                      ),                    ),                  ],                ),              ),            ),          );        },      ),    );    // --- SAU KHI USER BẤM XÁC NHẬN ---    if (confirmed == true && selectedTime != null) {      try {        DateTime selDT = DateTime(          d.year,          d.month,          d.day,          int.parse(selectedTime!.split(":")[0]),          int.parse(selectedTime!.split(":")[1]),        );        // 1. Lưu thông tin lịch hẹn vào Cloud Firestore        await FirebaseFirestore.instance.collection('appointments').add({          'userId': user?.uid,          'doctorName': doc['name'],          'patientName': _nameController.text.trim(),          'patientPhone': _phoneController.text.trim(),          'patientAddress': _addressController.text.trim(),          'patientEmail': _emailController.text.trim(),          'hospital': _selectedHospital,          'image': doc['image'],          'date': dateStr,          'time': selectedTime,          'dept': doc['dept'],          'fullDateTime': selDT.toIso8601String(),          'createdAt': FieldValue.serverTimestamp(),        });        // 2. ĐỒNG BỘ DỮ LIỆU LÊN GOOGLE SHEETS (Dùng Web App URL của bạn)        try {          const String googleScriptUrl =              "https://script.google.com/macros/s/AKfycbxM62i0w6_04AfIdE-qBud7t4iS9afdWBqRtAxok40uGIgYHQV2ue2-lSApUAdgo-kxJQ/exec";          http              .post(                Uri.parse(googleScriptUrl),                body: jsonEncode({                  'patientName': _nameController.text.trim(),                  'patientPhone': _phoneController.text.trim(),                  'patientAddress': _addressController.text.trim(),                  'patientEmail': _emailController.text.trim(),                  'doctorName': doc['name'],                  'hospital': _selectedHospital,                  'date': dateStr,                  'time': selectedTime,                  'dept': doc['dept'],                }),              )              .then((response) => print("Đã gửi đến Sheets: ${response.body}"));        } catch (e) {          print("Lỗi đồng bộ Sheets: $e");        }        _fetchAppointments(); // Làm mới danh sách lịch sử trong app        await _showNotification(          _nameController.text,          doc['name']!,          selectedTime!,        ); // Hiện thông báo đẩy        if (mounted)          ScaffoldMessenger.of(context).showSnackBar(            SnackBar(              content: Text(                isVietnamese ? "Đặt lịch thành công!" : "Booking success!",              ),              backgroundColor: Colors.green,            ),          );      } catch (e) {        debugPrint("Lỗi đặt lịch: $e");      }    }  }  // --- WIDGET RENDER TEXTFIELD NHẬP LIỆU ---  Widget _buildBookingTextField({    required TextEditingController controller,    required String label,    required IconData icon,    TextInputType keyboardType = TextInputType.text,    required Function(String) onChanged,  }) {    return TextField(      controller: controller,      onChanged: onChanged,      keyboardType: keyboardType,      decoration: InputDecoration(        labelText: label,        prefixIcon: Icon(icon),        filled: true,        fillColor: Theme.of(context).brightness == Brightness.dark            ? Colors.grey[800]            : Colors.grey[100],        border: OutlineInputBorder(          borderRadius: BorderRadius.circular(15),          borderSide: BorderSide.none,        ),      ),    );  }  // --- TAB CHATBOT ---  Widget _buildChatTab() {    return Column(      children: [        Align(          alignment: Alignment.centerRight,          child: TextButton.icon(            onPressed: _resetChat,            icon: const Icon(Icons.refresh, size: 18),            label: Text(lang['reset_chat']),          ),        ),        Expanded(          child: ListView.builder(            padding: const EdgeInsets.symmetric(horizontal: 20),            itemCount: _messages.length,            itemBuilder: (context, index) => _ChatBubble(              text: _messages[index]["text"],              isMe: _messages[index]["isMe"],            ),          ),        ),        if (_isTyping)          Padding(            padding: const EdgeInsets.only(left: 20, bottom: 10),            child: Align(              alignment: Alignment.centerLeft,              child: Text(                lang['bot_typing'],                style: const TextStyle(                  fontStyle: FontStyle.italic,                  color: Colors.grey,                  fontSize: 12,                ),              ),            ),          ),        _buildChatInputArea(),      ],    );  }  Widget _buildChatInputArea() {    return Container(      padding: const EdgeInsets.all(15),      color: Theme.of(context).scaffoldBackgroundColor,      child: Row(        children: [          Expanded(            child: TextField(              controller: _chatController,              decoration: InputDecoration(                hintText: lang['chat_hint'],                filled: true,                border: OutlineInputBorder(                  borderRadius: BorderRadius.circular(30),                  borderSide: BorderSide.none,                ),              ),            ),          ),          const SizedBox(width: 10),          CircleAvatar(            backgroundColor: Colors.blue,            child: IconButton(              icon: const Icon(Icons.send, color: Colors.white, size: 20),              onPressed: _handleSendMessage,            ),          ),        ],      ),    );  }  // --- TAB TRANG CHỦ ---  Widget _buildHomeTab() {    return SingleChildScrollView(      controller: _scrollController,      padding: const EdgeInsets.symmetric(horizontal: 20),      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          const SizedBox(height: 10),          Text(lang['welcome'], style: const TextStyle(color: Colors.grey)),          if (_selectedHospital == null) ...[            Text(              lang['select_hosp'],              style: const TextStyle(fontSize: 26, fontWeight: FontWeight.bold),            ),            const SizedBox(height: 8),            Text(              lang['hosp_desc'],              style: const TextStyle(color: Colors.grey, fontSize: 14),            ),            const SizedBox(height: 25),            _buildHospitalGrid(),          ] else ...[            Row(              mainAxisAlignment: MainAxisAlignment.spaceBetween,              children: [                Expanded(                  child: Text(                    _selectedHospital!,                    style: const TextStyle(                      fontSize: 22,                      fontWeight: FontWeight.bold,                      color: Colors.blue,                    ),                  ),                ),                TextButton.icon(                  onPressed: () => setState(() {                    _selectedHospital = null;                    _selectedDeptFilter = null;                  }),                  icon: const Icon(Icons.swap_horiz, size: 18),                  label: Text(lang['back_hosp']),                ),              ],            ),            const SizedBox(height: 15),            _buildSearchBar(),            const SizedBox(height: 20),            Row(              mainAxisAlignment: MainAxisAlignment.spaceBetween,              children: [                Text(                  lang['dept'],                  style: const TextStyle(                    fontSize: 18,                    fontWeight: FontWeight.bold,                  ),                ),                if (_selectedDeptFilter != null)                  TextButton(                    onPressed: () => setState(() => _selectedDeptFilter = null),                    child: Text(                      lang['all'],                      style: const TextStyle(fontSize: 12),                    ),                  ),              ],            ),            const SizedBox(height: 10),            _buildCategorySection(),            const SizedBox(height: 20),            _buildDoctorGrid(),          ],          const SizedBox(height: 40),        ],      ),    );  }  // --- LƯỚI DANH SÁCH BỆNH VIỆN ---  Widget _buildHospitalGrid() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('hospitals')          .orderBy('createdAt', descending: false)          .snapshots(),      builder: (context, snapshot) {        if (snapshot.hasError)          return const Center(child: Text("Lỗi tải bệnh viện"));        if (!snapshot.hasData)          return const Center(child: CircularProgressIndicator());        final docs = snapshot.data!.docs;        return ListView.builder(          shrinkWrap: true,          physics: const NeverScrollableScrollPhysics(),          itemCount: docs.length,          itemBuilder: (context, i) {            String hospName = docs[i]['name'];            return Container(              margin: const EdgeInsets.only(bottom: 15),              child: InkWell(                onTap: () => setState(() => _selectedHospital = hospName),                borderRadius: BorderRadius.circular(20),                child: Container(                  padding: const EdgeInsets.all(20),                  decoration: BoxDecoration(                    gradient: LinearGradient(                      colors: [Colors.blue.shade400, Colors.blue.shade700],                      begin: Alignment.topLeft,                      end: Alignment.bottomRight,                    ),                    borderRadius: BorderRadius.circular(20),                    boxShadow: [                      BoxShadow(                        color: Colors.blue.withOpacity(0.3),                        blurRadius: 10,                        offset: const Offset(0, 5),                      ),                    ],                  ),                  child: Row(                    children: [                      Container(                        padding: const EdgeInsets.all(12),                        decoration: const BoxDecoration(                          color: Colors.white24,                          shape: BoxShape.circle,                        ),                        child: const Icon(                          Icons.local_hospital_rounded,                          color: Colors.white,                          size: 30,                        ),                      ),                      const SizedBox(width: 20),                      Expanded(                        child: Column(                          crossAxisAlignment: CrossAxisAlignment.start,                          children: [                            Text(                              hospName,                              style: const TextStyle(                                color: Colors.white,                                fontWeight: FontWeight.bold,                                fontSize: 18,                              ),                            ),                            const SizedBox(height: 4),                            Text(                              isVietnamese                                  ? "Xem danh sách bác sĩ"                                  : "See doctors list",                              style: TextStyle(                                color: Colors.white.withOpacity(0.8),                                fontSize: 13,                              ),                            ),                          ],                        ),                      ),                      const Icon(                        Icons.arrow_forward_ios_rounded,                        color: Colors.white,                        size: 18,                      ),                    ],                  ),                ),              ),            );          },        );      },    );  }  Widget _buildSearchBar() => TextField(    decoration: InputDecoration(      hintText: lang['search_hint'],      prefixIcon: const Icon(Icons.search),      filled: true,      border: OutlineInputBorder(        borderRadius: BorderRadius.circular(15),        borderSide: BorderSide.none,      ),    ),  );  Widget _buildCategorySection() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('specialities')          .orderBy('createdAt', descending: false)          .snapshots(),      builder: (context, snapshot) {        if (!snapshot.hasData) return const SizedBox();        final specs = snapshot.data!.docs;        return SizedBox(          height: 100,          child: ListView.builder(            scrollDirection: Axis.horizontal,            itemCount: specs.length,            itemBuilder: (context, i) {              String name = specs[i]['name'];              return _catItem(                _getIconForSpeciality(name),                _getDisplayName(name),                name,              );            },          ),        );      },    );  }  Widget _catItem(IconData icon, String label, String deptKey) =>      GestureDetector(        onTap: () => setState(() => _selectedDeptFilter = deptKey),        child: Padding(          padding: const EdgeInsets.only(right: 20),          child: Column(            children: [              CircleAvatar(                radius: 28,                backgroundColor: _selectedDeptFilter == deptKey                    ? Colors.blue                    : Colors.blue.withOpacity(0.1),                child: Icon(                  icon,                  color: _selectedDeptFilter == deptKey                      ? Colors.white                      : Colors.blue,                  size: 28,                ),              ),              const SizedBox(height: 8),              Text(                label,                style: TextStyle(                  fontSize: 11,                  fontWeight: _selectedDeptFilter == deptKey                      ? FontWeight.bold                      : FontWeight.w500,                  color: _selectedDeptFilter == deptKey ? Colors.blue : null,                ),              ),            ],          ),        ),      );  Widget _buildDoctorGrid() {    return StreamBuilder<QuerySnapshot>(      stream: FirebaseFirestore.instance          .collection('doctors')          .orderBy('createdAt', descending: true)          .snapshots(),      builder: (context, snapshot) {        if (snapshot.connectionState == ConnectionState.waiting)          return const Center(child: CircularProgressIndicator());        final List<DocumentSnapshot> allDocs = snapshot.data!.docs;        return StreamBuilder<QuerySnapshot>(          stream: FirebaseFirestore.instance              .collection('hospitals')              .snapshots(),          builder: (ctx, hospSnapshot) {            if (!hospSnapshot.hasData) return const SizedBox();            List<String> registeredHospitals = hospSnapshot.data!.docs                .map(                  (d) => (d.data() as Map<String, dynamic>)['name'].toString(),                )                .toList();            final filteredDocs = allDocs.where((doc) {              final data = doc.data() as Map<String, dynamic>;              bool isOldDoctor = !registeredHospitals.contains(                data['hospital'] ?? '',              );              bool isMatchingNewDoctor =                  (data['hospital'] == _selectedHospital);              bool matchesDept =                  (_selectedDeptFilter == null) ||                  (data['dept'] == _selectedDeptFilter);              return (isOldDoctor || isMatchingNewDoctor) && matchesDept;            }).toList();            if (filteredDocs.isEmpty)              return const Center(                child: Padding(                  padding: EdgeInsets.all(20),                  child: Text("Không có bác sĩ nào phù hợp."),                ),              );            return GridView.builder(              shrinkWrap: true,              physics: const NeverScrollableScrollPhysics(),              gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(                crossAxisCount: 2,                mainAxisSpacing: 15,                crossAxisSpacing: 15,                childAspectRatio: 0.8,              ),              itemCount: filteredDocs.length,              itemBuilder: (ctx, i) {                final data = filteredDocs[i].data() as Map<String, dynamic>;                final doc = {                  'id': filteredDocs[i].id,                  'name': data['name'] ?? '',                  'dept': data['dept'] ?? '',                  'hospital': data['hospital'] ?? '',                  'image': data['image'] ?? '',                };                bool isAsset = !doc['image']!.startsWith('http');                return GestureDetector(                  onTap: () => _bookDoctor(doc),                  child: Container(                    decoration: BoxDecoration(                      color: Theme.of(context).cardTheme.color ?? Colors.white,                      borderRadius: BorderRadius.circular(15),                      border: Border.all(color: Colors.grey.withOpacity(0.1)),                    ),                    child: Column(                      children: [                        Expanded(                          child: ClipRRect(                            borderRadius: const BorderRadius.vertical(                              top: Radius.circular(15),                            ),                            child: isAsset                                ? Image.asset(                                    doc['image']!,                                    fit: BoxFit.cover,                                    width: double.infinity,                                    errorBuilder: (c, e, s) =>                                        const Icon(Icons.person, size: 50),                                  )                                : Image.network(                                    doc['image']!,                                    fit: BoxFit.cover,                                    width: double.infinity,                                    errorBuilder: (c, e, s) =>                                        const Icon(Icons.person, size: 50),                                  ),                          ),                        ),                        Padding(                          padding: const EdgeInsets.all(8),                          child: Column(                            children: [                              Text(                                doc['name']!,                                style: const TextStyle(                                  fontWeight: FontWeight.bold,                                  fontSize: 12,                                ),                                textAlign: TextAlign.center,                              ),                              Text(                                _getDisplayName(doc['dept']!),                                style: const TextStyle(                                  color: Colors.grey,                                  fontSize: 10,                                  fontStyle: FontStyle.italic,                                ),                              ),                              const SizedBox(height: 4),                              Text(                                lang['book_btn'],                                style: const TextStyle(                                  color: Colors.blue,                                  fontSize: 10,                                  fontWeight: FontWeight.bold,                                ),                              ),                            ],                          ),                        ),                      ],                    ),                  ),                );              },            );          },        );      },    );  }  // --- POPUP CHI TIẾT LỊCH HẸN (ĐÃ FIX OVERFLOW) ---  void _showAppointmentDetails(Map<String, dynamic> app) {    showModalBottomSheet(      context: context,      isScrollControlled: true,      shape: const RoundedRectangleBorder(        borderRadius: BorderRadius.vertical(top: Radius.circular(20)),      ),      builder: (ctx) {        return SafeArea(          child: Container(            padding: const EdgeInsets.all(20),            constraints: BoxConstraints(              maxHeight: MediaQuery.of(context).size.height * 0.85,            ),            child: Column(              mainAxisSize: MainAxisSize.min,              crossAxisAlignment: CrossAxisAlignment.start,              children: [                Center(                  child: Container(                    width: 40,                    height: 5,                    decoration: BoxDecoration(                      color: Colors.grey[300],                      borderRadius: BorderRadius.circular(10),                    ),                  ),                ),                const SizedBox(height: 20),                Text(                  lang['appt_details'],                  style: const TextStyle(                    fontSize: 20,                    fontWeight: FontWeight.bold,                    color: Colors.blue,                  ),                ),                const SizedBox(height: 15),                Flexible(                  child: SingleChildScrollView(                    child: Column(                      children: [                        _detailRow(                          Icons.medical_services,                          "Bác sĩ / Doctor",                          app['name'],                        ),                        _detailRow(                          Icons.category,                          lang['dept'],                          _getDisplayName(app['dept']),                        ),                        _detailRow(                          Icons.local_hospital,                          lang['select_hosp'],                          app['hospital'],                        ),                        _detailRow(                          Icons.access_time,                          "Thời gian / Time",                          "${app['time']} - ${app['date']}",                        ),                        const Divider(height: 30),                        _detailRow(                          Icons.person,                          lang['patient'],                          app['patient'],                        ),                        if (app['phone'].toString().isNotEmpty)                          _detailRow(Icons.phone, lang['phone'], app['phone']),                        if (app['email'].toString().isNotEmpty)                          _detailRow(Icons.email, lang['email'], app['email']),                        if (app['address'].toString().isNotEmpty)                          _detailRow(                            Icons.location_on,                            lang['address'],                            app['address'],                          ),                      ],                    ),                  ),                ),                const SizedBox(height: 20),                SizedBox(                  width: double.infinity,                  height: 50,                  child: ElevatedButton(                    onPressed: () => Navigator.pop(ctx),                    style: ElevatedButton.styleFrom(                      backgroundColor: Colors.blue,                      shape: RoundedRectangleBorder(                        borderRadius: BorderRadius.circular(15),                      ),                    ),                    child: Text(                      lang['close'],                      style: const TextStyle(                        color: Colors.white,                        fontWeight: FontWeight.bold,                        fontSize: 16,                      ),                    ),                  ),                ),              ],            ),          ),        );      },    );  }  Widget _detailRow(IconData icon, String title, String value) {    return Padding(      padding: const EdgeInsets.only(bottom: 12),      child: Row(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          Icon(icon, size: 20, color: Colors.grey),          const SizedBox(width: 10),          Expanded(            child: Column(              crossAxisAlignment: CrossAxisAlignment.start,              children: [                Text(                  title,                  style: const TextStyle(fontSize: 12, color: Colors.grey),                ),                Text(                  value,                  style: const TextStyle(                    fontSize: 15,                    fontWeight: FontWeight.w500,                  ),                  softWrap: true,                ),              ],            ),          ),        ],      ),    );  }  // --- TAB LỊCH SỬ ---  Widget _buildHistoryTab() {    final groupedData = _groupAppointmentsByMonth();    return Padding(      padding: const EdgeInsets.all(20),      child: Column(        crossAxisAlignment: CrossAxisAlignment.start,        children: [          Text(            lang['my_booking'],            style: const TextStyle(              fontSize: 22,              fontWeight: FontWeight.bold,              color: Colors.blue,            ),          ),          const SizedBox(height: 15),          Expanded(            child: bookedAppointments.isEmpty                ? Center(child: Text(lang['no_booking']))                : ListView.builder(                    itemCount: groupedData.length,                    itemBuilder: (context, index) {                      String month = groupedData.keys.elementAt(index);                      List<Map<String, dynamic>> apps = groupedData[month]!;                      return Column(                        crossAxisAlignment: CrossAxisAlignment.start,                        children: [                          Padding(                            padding: const EdgeInsets.symmetric(vertical: 10),                            child: Row(                              children: [                                Container(                                  padding: const EdgeInsets.symmetric(                                    horizontal: 12,                                    vertical: 6,                                  ),                                  decoration: BoxDecoration(                                    color: Colors.blue.withOpacity(0.1),                                    borderRadius: BorderRadius.circular(20),                                  ),                                  child: Text(                                    month,                                    style: const TextStyle(                                      fontWeight: FontWeight.bold,                                      color: Colors.blue,                                      fontSize: 14,                                    ),                                  ),                                ),                                const Expanded(child: Divider(indent: 10)),                              ],                            ),                          ),                          ...apps.map((app) {                            bool isAsset = !app['image'].startsWith('http');                            return Card(                              margin: const EdgeInsets.only(bottom: 10),                              elevation: 2,                              shape: RoundedRectangleBorder(                                borderRadius: BorderRadius.circular(15),                              ),                              child: ListTile(                                onTap: () => _showAppointmentDetails(app),                                leading: CircleAvatar(                                  backgroundImage: isAsset                                      ? AssetImage(app['image'])                                            as ImageProvider                                      : NetworkImage(app['image']),                                ),                                title: Text(                                  app['name'],                                  style: const TextStyle(                                    fontWeight: FontWeight.bold,                                  ),                                ),                                subtitle: Text(                                  "${lang['patient']}: ${app['patient']}\n🏢 ${app['hospital']}\n📅 ${app['date']} - ${app['time']}",                                  style: const TextStyle(fontSize: 12),                                ),                                isThreeLine: true,                                trailing: IconButton(                                  icon: const Icon(                                    Icons.delete_outline,                                    color: Colors.redAccent,                                  ),                                  onPressed: () async {                                    await FirebaseFirestore.instance                                        .collection('appointments')                                        .doc(app['id'])                                        .delete();                                    _fetchAppointments();                                  },                                ),                              ),                            );                          }).toList(),                        ],                      );                    },                  ),          ),        ],      ),    );  }  // --- TAB CÁ NHÂN (HỒ SƠ) ---  Widget _buildProfileTab() {    final themeProvider = Provider.of<ThemeProvider>(context);    final isDark = themeProvider.isDarkMode;    return SingleChildScrollView(      padding: const EdgeInsets.all(20),      child: Column(        children: [          Container(            padding: const EdgeInsets.all(20),            decoration: BoxDecoration(              color: isDark ? Colors.grey[800] : Colors.white,              borderRadius: BorderRadius.circular(25),              boxShadow: [                BoxShadow(                  color: Colors.blue.withOpacity(0.1),                  blurRadius: 20,                  offset: const Offset(0, 10),                ),              ],            ),            child: Column(              children: [                Stack(                  alignment: Alignment.bottomRight,                  children: [                    Container(                      decoration: BoxDecoration(                        shape: BoxShape.circle,                        border: Border.all(                          color: Colors.blue.shade100,                          width: 4,                        ),                      ),                      child: CircleAvatar(                        radius: 50,                        backgroundColor: Colors.blue.shade50,                        backgroundImage: _profileImagePath.isNotEmpty                            ? FileImage(File(_profileImagePath))                            : null,                        child: _profileImagePath.isEmpty                            ? Icon(                                Icons.person,                                size: 50,                                color: Colors.blue.shade300,                              )                            : null,                      ),                    ),                    GestureDetector(                      onTap: _pickImage,                      child: Container(                        padding: const EdgeInsets.all(8),                        decoration: BoxDecoration(                          color: Colors.blue,                          shape: BoxShape.circle,                          border: Border.all(color: Colors.white, width: 2),                        ),                        child: const Icon(                          Icons.camera_alt,                          size: 16,                          color: Colors.white,                        ),                      ),                    ),                  ],                ),                const SizedBox(height: 15),                Row(                  mainAxisAlignment: MainAxisAlignment.center,                  children: [                    Text(                      _userName,                      style: const TextStyle(                        fontSize: 22,                        fontWeight: FontWeight.bold,                      ),                    ),                    const SizedBox(width: 8),                    GestureDetector(                      onTap: _editName,                      child: const Icon(                        Icons.edit_square,                        color: Colors.blue,                        size: 18,                      ),                    ),                  ],                ),                const SizedBox(height: 5),                Text(                  user?.email ?? "User",                  style: const TextStyle(fontSize: 14, color: Colors.grey),                ),              ],            ),          ),          const SizedBox(height: 30),          Container(            decoration: BoxDecoration(              color: isDark ? Colors.grey[800] : Colors.white,              borderRadius: BorderRadius.circular(25),              boxShadow: [                BoxShadow(                  color: Colors.grey.withOpacity(0.05),                  blurRadius: 20,                  offset: const Offset(0, 10),                ),              ],            ),            child: Column(              children: [                ListTile(                  contentPadding: const EdgeInsets.symmetric(                    horizontal: 20,                    vertical: 5,                  ),                  leading: Container(                    padding: const EdgeInsets.all(10),                    decoration: BoxDecoration(                      color: Colors.amber.withOpacity(0.15),                      shape: BoxShape.circle,                    ),                    child: Icon(                      isDark ? Icons.dark_mode : Icons.light_mode,                      color: Colors.amber,                    ),                  ),                  title: Text(                    lang['dark_mode'],                    style: const TextStyle(fontWeight: FontWeight.w600),                  ),                  trailing: Switch(                    value: isDark,                    activeColor: Colors.blue,                    onChanged: (v) => themeProvider.toggleTheme(),                  ),                ),                if (user?.email == "quocthang15082004@gmail.com") ...[                  _buildMenuDivider(),                  _buildModernMenu(                    Icons.admin_panel_settings,                    lang['admin_panel'],                    Colors.indigo,                    () {                      Navigator.push(                        context,                        MaterialPageRoute(                          builder: (c) => AdminPage(isVietnamese: isVietnamese),                        ),                      );                    },                  ),                ],                _buildMenuDivider(),                _buildModernMenu(                  Icons.lock_outline,                  lang['change_pw'],                  Colors.green,                  () {                    _showChangePasswordDialog();                  },                ),                _buildMenuDivider(),                _buildModernMenu(                  Icons.logout,                  lang['logout'],                  Colors.redAccent,                  () async {                    await FirebaseAuth.instance.signOut();                    Navigator.pushReplacement(                      context,                      MaterialPageRoute(builder: (c) => Login()),                    );                  },                  isRed: true,                ),              ],            ),          ),          const SizedBox(height: 20),        ],      ),    );  }  Widget _buildMenuDivider() {    return Padding(      padding: const EdgeInsets.symmetric(horizontal: 20),      child: Divider(color: Colors.grey.withOpacity(0.2), height: 1),    );  }  Widget _buildModernMenu(    IconData icon,    String title,    Color iconColor,    VoidCallback onTap, {    bool isRed = false,  }) {    return ListTile(      contentPadding: const EdgeInsets.symmetric(horizontal: 20, vertical: 5),      leading: Container(        padding: const EdgeInsets.all(10),        decoration: BoxDecoration(          color: isRed              ? Colors.red.withOpacity(0.1)              : iconColor.withOpacity(0.15),          shape: BoxShape.circle,        ),        child: Icon(icon, color: isRed ? Colors.redAccent : iconColor),      ),      title: Text(        title,        style: TextStyle(          fontWeight: FontWeight.w600,          color: isRed ? Colors.redAccent : null,        ),      ),      trailing: const Icon(        Icons.arrow_forward_ios,        size: 16,        color: Colors.grey,      ),      onTap: onTap,    );  }  // --- ĐIỀU KHIỂN CHUYỂN TAB ---  Widget _getBody() {    switch (_currentIndex) {      case 0:        return _buildHomeTab();      case 1:        return _buildHistoryTab();      case 2:        return _buildChatTab();      case 3:        return _buildProfileTab();      default:        return _buildHomeTab();    }  }  @override  Widget build(BuildContext context) {    return Scaffold(      appBar: AppBar(        title: const Text(          "Mediapp",          style: TextStyle(color: Colors.blue, fontWeight: FontWeight.bold),        ),        backgroundColor: Theme.of(context).appBarTheme.backgroundColor,        elevation: 0,        actions: [          IconButton(            icon: const Icon(Icons.phone, color: Colors.red),            onPressed: () => _makePhoneCall("19001234"),          ),          TextButton(            onPressed: () async {              setState(() => isVietnamese = !isVietnamese);              final prefs = await SharedPreferences.getInstance();              await prefs.setBool('isVietnamese', isVietnamese);              _resetChat();            },            child: Text(              isVietnamese ? "EN" : "VN",              style: const TextStyle(                color: Colors.blue,                fontWeight: FontWeight.bold,              ),            ),          ),        ],      ),      body: _getBody(),      bottomNavigationBar: BottomNavigationBar(        currentIndex: _currentIndex,        onTap: (v) => setState(() => _currentIndex = v),        selectedItemColor: Colors.blue,        unselectedItemColor: Colors.grey,        type: BottomNavigationBarType.fixed,        items: [          BottomNavigationBarItem(            icon: const Icon(Icons.home),            label: lang['home'],          ),          BottomNavigationBarItem(            icon: const Icon(Icons.calendar_today),            label: lang['booking'],          ),          BottomNavigationBarItem(            icon: const Icon(Icons.message),            label: lang['chat'],          ),          BottomNavigationBarItem(            icon: const Icon(Icons.person),            label: lang['profile'],          ),        ],      ),    );  }}// --- WIDGET BONG BÓNG CHAT ---class _ChatBubble extends StatelessWidget {  final String text;  final bool isMe;  const _ChatBubble({required this.text, required this.isMe});  @override  Widget build(BuildContext context) {    return Align(      alignment: isMe ? Alignment.centerRight : Alignment.centerLeft,      child: Container(        margin: const EdgeInsets.symmetric(vertical: 5),        padding: const EdgeInsets.all(12),        decoration: BoxDecoration(          color: isMe              ? Colors.blue              : (Theme.of(context).brightness == Brightness.dark                    ? Colors.grey[800]                    : Colors.grey.shade200),          borderRadius: BorderRadius.circular(15),        ),        child: Text(          text,          style: TextStyle(            color: isMe                ? Colors.white                : (Theme.of(context).brightness == Brightness.dark                      ? Colors.white                      : Colors.black),          ),        ),      ),    );  }}